using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// Procedurally generates race tracks with configurable difficulty.
/// Ensures consistent training across NEAT generations and PPO episodes.
/// </summary>
namespace CarExperiment
{
    public class TrackGenerator : MonoBehaviour
    {
        [Header("Track Prefabs")] [Tooltip("Straight road piece prefab")]
        public GameObject straightPiece;

        [Tooltip("45-degree turn piece prefab")]
        public GameObject turn45Piece;

        [Tooltip("Goal/checkpoint piece prefab")]
        public GameObject goalPiece;

        [Header("Track Configuration")] [Tooltip("Number of road pieces in the track")]
        public int trackLength = 20;

        [Tooltip("Maximum attempts to generate a valid non-intersecting track before giving up")]
        public int maxGenerationAttempts = 10;

        [Tooltip("Difficulty level (0-1): 0=easy (mostly straight), 1=hard (many turns)")] [Range(0f, 1f)]
        public float difficulty = 0.5f;

        [Tooltip("Probability of 90-degree turn vs 45-degree turn at high difficulty")] [Range(0f, 1f)]
        public float sharpTurnProbability = 0.3f;

        [Tooltip("Random seed for reproducible tracks (0 = random seed)")]
        public int seed = 0;

        [Header("Curriculum Learning")] [Tooltip("Gradually increase difficulty over generations/episodes")]
        public bool useCurriculum = false;

        [Tooltip("Starting difficulty for curriculum")] [Range(0f, 1f)]
        public float startDifficulty = 0.1f;

        [Tooltip("Episodes/generations to reach max difficulty")]
        public int curriculumSteps = 100;

        [Header("Track Appearance")] [Tooltip("Width of each road piece")]
        public float pieceLength = 2f;

        [Tooltip("Number of wall segments to use on turns to follow curvature")]
        public int wallSegmentsPerTurn = 8;

        [Tooltip("Thickness of the wall (X scale contribution)")]
        public float wallThickness = 0.05f;

        [Header("Track Walls")] [Tooltip("Wall prefab to instantiate along the track")]
        public GameObject wallPrefab;

        [Tooltip("Distance from road center to wall (half road width + half wall width)")]
        public float wallOffset = 2.7f;

        [Header("Wall Trimming")]
        [Tooltip("Inset amount to trim the right wall before a right turn (in meters)")]
        public float wallEndInset = 2f;

        private Vector3 lastWallEndL = Vector3.zero;
        private Vector3 lastWallEndR = Vector3.zero;
        private Quaternion lastPieceRot = Quaternion.identity;

        // Track data
        private List<GameObject> currentTrackPieces;
        private List<GameObject> currentWallPieces;
        private Vector3 currentPosition;
        private Quaternion currentRotation;
        private int generationCount = 0;

        // Track statistics (for analysis)
        public struct TrackStats
        {
            public int StraightCount;
            public int Turn45Count;
            public float TotalTurnAngle;
            public float ActualDifficulty;
        }

        private struct PieceInfo
        {
            public PieceType Type;
            public Vector3 Pos;
            public Quaternion Rot;
        }

        private TrackStats lastTrackStats;

        void Start()
        {
            currentTrackPieces = new List<GameObject>();
            currentWallPieces = new List<GameObject>();
            GenerateTrack(Random.Range(0, 1000000));;
        }

        /// <summary>
        /// Generates a new procedural track. Call this at the start of each NEAT generation or PPO episode.
        /// </summary>
        ///
        public void GenerateTrack(int externalSeed)
        {
            // Force deterministic generation
            Random.InitState(externalSeed);

            GenerateNewTrackWithSeed();
        }

        public void GenerateNewTrackWithSeed()
        {

            ClearTrack();
            generationCount++;

            // Set random seed for reproducibility if specified
            // if (seed != 0)
            // {
            //     Random.InitState(seed + generationCount);
            // }

            List<TrackGenerator.PieceInfo> pieces = new List<TrackGenerator.PieceInfo>();
            bool generationSuccessful = false;
            int attempts = 0;

            while (!generationSuccessful && attempts < maxGenerationAttempts)
            {
                attempts++;
                pieces.Clear();
                Vector3 tempPos = transform.position;
                Quaternion tempRot = transform.rotation;
                PieceType nextType = PieceType.Straight;
                bool foundIntersectionInThisAttempt = false;

                for (int i = 0; i < trackLength; i++)
                {
                    if (i == trackLength - 1)
                    {
                        pieces.Add(new TrackGenerator.PieceInfo { Type = PieceType.Straight, Pos = tempPos, Rot = tempRot });
                    }
                    else
                    {
                        // Intersection check and piece selection
                        PieceType selected = nextType;
                        // Try types in this order: desired, straight, left, right
                        PieceType[] attemptTypes = { nextType, PieceType.Straight, PieceType.Turn45Left, PieceType.Turn45Right, PieceType.Turn90Left, PieceType.Turn90Right };
                        bool foundValidPiece = false;

                        foreach (PieceType attempt in attemptTypes)
                        {
                            Vector3 nextPos = GetNextPosition(tempPos, tempRot, attempt);
                            bool intersects = false;

                            // Start checking against previous pieces (skip the immediate previous one)
                            for (int j = 0; j < pieces.Count - 1; j++)
                            {
                                if (Vector3.Distance(nextPos, pieces[j].Pos) < pieceLength * 1.5f)
                                {
                                    intersects = true;
                                    break;
                                }
                            }

                            if (!intersects)
                            {
                                selected = attempt;
                                foundValidPiece = true;
                                break;
                            }
                        }

                        if (!foundValidPiece)
                        {
                            foundIntersectionInThisAttempt = true;
                            break; // Fail this entire track attempt
                        }

                        pieces.Add(new TrackGenerator.PieceInfo { Type = selected, Pos = tempPos, Rot = tempRot });
                        tempPos = GetNextPosition(tempPos, tempRot, selected);
                        tempRot = GetNextRotation(tempRot, selected);
                        nextType = SelectPieceType(CalculateCurrentDifficulty());
                    }
                }

                if (!foundIntersectionInThisAttempt)
                {
                    generationSuccessful = true;
                }
            }

            lastWallEndL = Vector3.zero;
            lastWallEndR = Vector3.zero;

            TrackStats stats = new TrackStats();
            for (int i = 0; i < pieces.Count; i++)
            {
                TrackGenerator.PieceInfo info = pieces[i];
                GameObject piece;

                if (i == trackLength - 1)
                {
                    piece = Instantiate(goalPiece, info.Pos, info.Rot, transform);
                    piece.name = $"Goal_Piece_{i}";
                    var teleport = piece.AddComponent<GoalTeleport>();
                }
                else
                {
                    switch (info.Type)
                    {
                        case PieceType.Straight:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Straight_Piece_{i}";
                            stats.StraightCount++;
                            break;
                        case PieceType.Turn45Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn45Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn90Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        case PieceType.Turn90Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        default:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Default_Piece_{i}";
                            stats.StraightCount++;
                            break;
                    }
                }

                currentTrackPieces.Add(piece);

                // Set PieceNumber for road pieces (not goal)
                if (i < trackLength - 1)
                {
                    RoadPiece rp = piece.GetComponentInChildren<RoadPiece>();
                    if (rp != null)
                    {
                        rp.PieceNumber = i;
                    }
                }

                if (wallPrefab != null && i < pieces.Count - 1)
                {
                    // Start from where the previous wall ended (or compute fresh for piece 0)
                    Vector3 wallStartL = (lastWallEndL != Vector3.zero)
                        ? lastWallEndL
                        : info.Pos + info.Rot * (Vector3.left * wallOffset);

                    Vector3 wallStartR = (lastWallEndR != Vector3.zero)
                        ? lastWallEndR
                        : info.Pos + info.Rot * (Vector3.right * wallOffset);

                    Quaternion exitRot = GetNextRotation(info.Rot, info.Type);
                    Vector3 exitPos = GetNextPosition(info.Pos, info.Rot, info.Type);

                    Vector3 wallEndL = exitPos + exitRot * (Vector3.left * wallOffset);
                    Vector3 wallEndR = exitPos + exitRot * (Vector3.right * wallOffset);

                    if (pieces[i + 1].Type == PieceType.Turn45Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn45Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn90Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset * 2f);

                    if (pieces[i + 1].Type == PieceType.Turn90Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset * 2f);

                    // Trim the INNER side before a turn, and save that trimmed point
                    // so the turn piece's inner wall can start exactly from there
                    // if (pieces[i + 1].Type == PieceType.Turn45Left)
                    //     wallEndL = wallEndL - info.Rot * (Vector3.forward * wallEndInset);
                    //
                    // if (pieces[i + 1].Type == PieceType.Turn45Right)
                    //     wallEndR = wallEndR - info.Rot * (Vector3.forward * wallEndInset);

                    lastWallEndL = wallEndL;
                    lastWallEndR = wallEndR;

                    PlaceWall(wallStartL, wallEndL, $"WallL_{i}", wallThickness);
                    PlaceWall(wallStartR, wallEndR, $"WallR_{i}", wallThickness);

                    // After placing walls, store current piece's rotation for next iteration
                    lastPieceRot = info.Rot;
                    if (i == 0)
                    {
                        Vector3 backL = info.Pos + info.Rot * (Vector3.left * wallOffset);
                        Vector3 backR = info.Pos + info.Rot * (Vector3.right * wallOffset);
                        PlaceWall(backL, backR, "BackWall", wallThickness);
                    }
                }
            }

            // Removed stray currentWallPieces.Add(wall); which was outside any function and caused errors.
        }

        private Vector3 GetNextPosition(Vector3 startPos, Quaternion startRot, PieceType type)
        {
            Vector3 pos = startPos;
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
                pos += rot * (-Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
                pos += rot * (Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (-Vector3.right * 2f + -Vector3.forward * 2f);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (Vector3.right * 2f + -Vector3.forward * 2f);
            }
            pos += rot * Vector3.forward * pieceLength;
            return pos;
        }

        private Quaternion GetNextRotation(Quaternion startRot, PieceType type)
        {
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
            }
            return rot;
        }

        /// <summary>
        /// Selects a piece type based on current difficulty and previous piece orientation.
        /// </summary>
        private PieceType SelectPieceType(float currentDifficulty)
        {
            float roll = Random.value;

            // At low difficulty, mostly straight pieces
            // At high difficulty, more turns
            if (roll > currentDifficulty)
            {
                return PieceType.Straight;
            }
            else
            {
                // Choose between 45-degree and 90-degree turns based on sharpTurnProbability
                bool useSharpTurn = Random.value < sharpTurnProbability;
                bool turnLeft = Random.value < 0.5f;

                if (useSharpTurn)
                {
                    return turnLeft ? PieceType.Turn90Left : PieceType.Turn90Right;
                }
                else
                {
                    return turnLeft ? PieceType.Turn45Left : PieceType.Turn45Right;
                }
            }
        }

        /// <summary>
        /// Calculates current difficulty based on curriculum settings.
        /// </summary>
        private float CalculateCurrentDifficulty()
        {
            if (!useCurriculum)
            {
                return difficulty;
            }

            // Gradually increase from startDifficulty to difficulty over curriculumSteps
            float progress = Mathf.Min(generationCount / (float)curriculumSteps, 1f);
            return Mathf.Lerp(startDifficulty, difficulty, progress);
        }

        /// <summary>
        /// Clears the current track.
        /// </summary>
        private void ClearTrack()
        {
            foreach (GameObject piece in currentTrackPieces)
            {
                Destroy(piece);
            }

            currentTrackPieces.Clear();
            foreach (GameObject wall in currentWallPieces)
            {
                Destroy(wall);
            }

            currentWallPieces.Clear();
        }

        /// <summary>
        /// Gets statistics about the last generated track (for thesis analysis).
        /// </summary>
        public TrackStats GetLastTrackStats()
        {
            return lastTrackStats;
        }

        /// <summary>
        /// Gets the current generation/episode count.
        /// </summary>
        public int GetGenerationCount()
        {
            return generationCount;
        }

        /// <summary>
        /// Resets the generation counter (useful when switching between NEAT/PPO experiments).
        /// </summary>
        public void ResetGenerationCount()
        {
            generationCount = 0;
        }

        void OnDrawGizmos()
        {
            // Visualize track in editor
            if (currentTrackPieces.Count > 0)
            {
                Gizmos.color = Color.cyan;
                for (int i = 0; i < currentTrackPieces.Count - 1; i++)
                {
                    Gizmos.DrawLine(
                        currentTrackPieces[i].transform.position + Vector3.up * 0.5f,
                        currentTrackPieces[i + 1].transform.position + Vector3.up * 0.5f
                    );
                }
            }
        }

        private void PlaceWall(Vector3 start, Vector3 end, string wallName, float thickness)
        {
            Vector3 diff = end - start;
            //Debug.Log(end + " - " + start + " = " + diff);
            float dist = diff.magnitude;
            if (dist < 0.001f) return;

            Vector3 wallPos = start + diff * 0.5f;
            Quaternion wallRot = Quaternion.LookRotation(diff);

            GameObject wall = Instantiate(wallPrefab, wallPos, wallRot, transform);
            wall.name = wallName;

            // Clean scale: thickness (X), height (Y), and distance (Z)
            // Use 1.0f for Y to preserve prefab height relative to its transform
            wall.transform.localScale = new Vector3(thickness, wall.transform.localScale.y, dist);

            currentWallPieces.Add(wall);
        }

        private enum PieceType
        {
            Straight,
            Turn45Left,
            Turn45Right,
            Turn90Left,
            Turn90Right
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// Procedurally generates race tracks with configurable difficulty.
/// Ensures consistent training across NEAT generations and PPO episodes.
/// </summary>
namespace CarExperiment
{
    public class TrackGenerator : MonoBehaviour
    {
        [Header("Track Prefabs")] [Tooltip("Straight road piece prefab")]
        public GameObject straightPiece;

        [Tooltip("45-degree turn piece prefab")]
        public GameObject turn45Piece;

        [Tooltip("Goal/checkpoint piece prefab")]
        public GameObject goalPiece;

        [Header("Track Configuration")] [Tooltip("Number of road pieces in the track")]
        public int trackLength = 20;

        [Tooltip("Maximum attempts to generate a valid non-intersecting track before giving up")]
        public int maxGenerationAttempts = 10;

        [Tooltip("Difficulty level (0-1): 0=easy (mostly straight), 1=hard (many turns)")] [Range(0f, 1f)]
        public float difficulty = 0.5f;

        [Tooltip("Probability of 90-degree turn vs 45-degree turn at high difficulty")] [Range(0f, 1f)]
        public float sharpTurnProbability = 0.3f;

        [Tooltip("Random seed for reproducible tracks (0 = random seed)")]
        public int seed = 0;

        [Header("Curriculum Learning")] [Tooltip("Gradually increase difficulty over generations/episodes")]
        public bool useCurriculum = false;

        [Tooltip("Starting difficulty for curriculum")] [Range(0f, 1f)]
        public float startDifficulty = 0.1f;

        [Tooltip("Episodes/generations to reach max difficulty")]
        public int curriculumSteps = 100;

        [Header("Track Appearance")] [Tooltip("Width of each road piece")]
        public float pieceLength = 2f;

        [Tooltip("Number of wall segments to use on turns to follow curvature")]
        public int wallSegmentsPerTurn = 8;

        [Tooltip("Thickness of the wall (X scale contribution)")]
        public float wallThickness = 0.05f;

        [Header("Track Walls")] [Tooltip("Wall prefab to instantiate along the track")]
        public GameObject wallPrefab;

        [Tooltip("Distance from road center to wall (half road width + half wall width)")]
        public float wallOffset = 2.7f;

        [Header("Wall Trimming")]
        [Tooltip("Inset amount to trim the right wall before a right turn (in meters)")]
        public float wallEndInset = 2f;

        private Vector3 lastWallEndL = Vector3.zero;
        private Vector3 lastWallEndR = Vector3.zero;
        private Quaternion lastPieceRot = Quaternion.identity;

        // Track data
        private List<GameObject> currentTrackPieces;
        private List<GameObject> currentWallPieces;
        private Vector3 currentPosition;
        private Quaternion currentRotation;
        private int generationCount = 0;

        // Track statistics (for analysis)
        public struct TrackStats
        {
            public int StraightCount;
            public int Turn45Count;
            public float TotalTurnAngle;
            public float ActualDifficulty;
        }

        private struct PieceInfo
        {
            public PieceType Type;
            public Vector3 Pos;
            public Quaternion Rot;
        }

        private TrackStats lastTrackStats;

        void Start()
        {
            currentTrackPieces = new List<GameObject>();
            currentWallPieces = new List<GameObject>();
            GenerateTrack(Random.Range(0, 1000000));;
        }

        /// <summary>
        /// Generates a new procedural track. Call this at the start of each NEAT generation or PPO episode.
        /// </summary>
        /// 
        public void GenerateTrack(int externalSeed)
        {
            // Force deterministic generation
            Random.InitState(externalSeed);

            GenerateNewTrackWithSeed();
        }

        public void GenerateNewTrackWithSeed()
        {

            ClearTrack();
            generationCount++;

            // Set random seed for reproducibility if specified
            // if (seed != 0)
            // {
            //     Random.InitState(seed + generationCount);
            // }

            List<TrackGenerator.PieceInfo> pieces = new List<TrackGenerator.PieceInfo>();
            bool generationSuccessful = false;
            int attempts = 0;

            while (!generationSuccessful && attempts < maxGenerationAttempts)
            {
                attempts++;
                pieces.Clear();
                Vector3 tempPos = transform.position;
                Quaternion tempRot = transform.rotation;
                PieceType nextType = PieceType.Straight;
                bool foundIntersectionInThisAttempt = false;

                for (int i = 0; i < trackLength; i++)
                {
                    if (i == trackLength - 1)
                    {
                        pieces.Add(new TrackGenerator.PieceInfo { Type = PieceType.Straight, Pos = tempPos, Rot = tempRot });
                    }
                    else
                    {
                        // Intersection check and piece selection
                        PieceType selected = nextType;
                        // Try types in this order: desired, straight, left, right
                        PieceType[] attemptTypes = { nextType, PieceType.Straight, PieceType.Turn45Left, PieceType.Turn45Right, PieceType.Turn90Left, PieceType.Turn90Right };
                        bool foundValidPiece = false;

                        foreach (PieceType attempt in attemptTypes)
                        {
                            Vector3 nextPos = GetNextPosition(tempPos, tempRot, attempt);
                            bool intersects = false;

                            // Start checking against previous pieces (skip the immediate previous one)
                            for (int j = 0; j < pieces.Count - 1; j++)
                            {
                                if (Vector3.Distance(nextPos, pieces[j].Pos) < pieceLength * 1.5f)
                                {
                                    intersects = true;
                                    break;
                                }
                            }

                            if (!intersects)
                            {
                                selected = attempt;
                                foundValidPiece = true;
                                break;
                            }
                        }

                        if (!foundValidPiece)
                        {
                            foundIntersectionInThisAttempt = true;
                            break; // Fail this entire track attempt
                        }

                        pieces.Add(new TrackGenerator.PieceInfo { Type = selected, Pos = tempPos, Rot = tempRot });
                        tempPos = GetNextPosition(tempPos, tempRot, selected);
                        tempRot = GetNextRotation(tempRot, selected);
                        nextType = SelectPieceType(CalculateCurrentDifficulty());
                    }
                }

                if (!foundIntersectionInThisAttempt)
                {
                    generationSuccessful = true;
                }
            }

            lastWallEndL = Vector3.zero;
            lastWallEndR = Vector3.zero;

            TrackStats stats = new TrackStats();
            for (int i = 0; i < pieces.Count; i++)
            {
                TrackGenerator.PieceInfo info = pieces[i];
                GameObject piece;

                if (i == trackLength - 1)
                {
                    piece = Instantiate(goalPiece, info.Pos, info.Rot, transform);
                    piece.name = $"Goal_Piece_{i}";
                    var teleport = piece.AddComponent<GoalTeleport>();
                }
                else
                {
                    switch (info.Type)
                    {
                        case PieceType.Straight:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Straight_Piece_{i}";
                            stats.StraightCount++;
                            break;
                        case PieceType.Turn45Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn45Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn90Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        case PieceType.Turn90Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        default:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Default_Piece_{i}";
                            stats.StraightCount++;
                            break;
                    }
                }

                currentTrackPieces.Add(piece);

                // Set PieceNumber for road pieces (not goal)
                if (i < trackLength - 1)
                {
                    RoadPiece rp = piece.GetComponentInChildren<RoadPiece>();
                    if (rp != null)
                    {
                        rp.PieceNumber = i;
                    }
                }

                if (wallPrefab != null && i < pieces.Count - 1)
                {
                    // Start from where the previous wall ended (or compute fresh for piece 0)
                    Vector3 wallStartL = (lastWallEndL != Vector3.zero)
                        ? lastWallEndL
                        : info.Pos + info.Rot * (Vector3.left * wallOffset);

                    Vector3 wallStartR = (lastWallEndR != Vector3.zero)
                        ? lastWallEndR
                        : info.Pos + info.Rot * (Vector3.right * wallOffset);

                    Quaternion exitRot = GetNextRotation(info.Rot, info.Type);
                    Vector3 exitPos = GetNextPosition(info.Pos, info.Rot, info.Type);

                    Vector3 wallEndL = exitPos + exitRot * (Vector3.left * wallOffset);
                    Vector3 wallEndR = exitPos + exitRot * (Vector3.right * wallOffset);

                    if (pieces[i + 1].Type == PieceType.Turn45Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn45Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn90Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset * 2f);

                    if (pieces[i + 1].Type == PieceType.Turn90Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset * 2f);

                    // Trim the INNER side before a turn, and save that trimmed point
                    // so the turn piece's inner wall can start exactly from there
                    // if (pieces[i + 1].Type == PieceType.Turn45Left)
                    //     wallEndL = wallEndL - info.Rot * (Vector3.forward * wallEndInset);
                    //
                    // if (pieces[i + 1].Type == PieceType.Turn45Right)
                    //     wallEndR = wallEndR - info.Rot * (Vector3.forward * wallEndInset);

                    lastWallEndL = wallEndL;
                    lastWallEndR = wallEndR;

                    PlaceWall(wallStartL, wallEndL, $"WallL_{i}", wallThickness);
                    PlaceWall(wallStartR, wallEndR, $"WallR_{i}", wallThickness);

                    // After placing walls, store current piece's rotation for next iteration
                    lastPieceRot = info.Rot;
                    if (i == 0)
                    {
                        Vector3 backL = info.Pos + info.Rot * (Vector3.left * wallOffset);
                        Vector3 backR = info.Pos + info.Rot * (Vector3.right * wallOffset);
                        PlaceWall(backL, backR, "BackWall", wallThickness);
                    }
                }
            }

            // Removed stray currentWallPieces.Add(wall); which was outside any function and caused errors.
        }

        private Vector3 GetNextPosition(Vector3 startPos, Quaternion startRot, PieceType type)
        {
            Vector3 pos = startPos;
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
                pos += rot * (-Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
                pos += rot * (Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (-Vector3.right * 2f + -Vector3.forward * 2f);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (Vector3.right * 2f + -Vector3.forward * 2f);
            }
            pos += rot * Vector3.forward * pieceLength;
            return pos;
        }

        private Quaternion GetNextRotation(Quaternion startRot, PieceType type)
        {
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
            }
            return rot;
        }

        /// <summary>
        /// Selects a piece type based on current difficulty and previous piece orientation.
        /// </summary>
        private PieceType SelectPieceType(float currentDifficulty)
        {
            float roll = Random.value;

            // At low difficulty, mostly straight pieces
            // At high difficulty, more turns
            if (roll > currentDifficulty)
            {
                return PieceType.Straight;
            }
            else
            {
                // Choose between 45-degree and 90-degree turns based on sharpTurnProbability
                bool useSharpTurn = Random.value < sharpTurnProbability;
                bool turnLeft = Random.value < 0.5f;

                if (useSharpTurn)
                {
                    return turnLeft ? PieceType.Turn90Left : PieceType.Turn90Right;
                }
                else
                {
                    return turnLeft ? PieceType.Turn45Left : PieceType.Turn45Right;
                }
            }
        }

        /// <summary>
        /// Calculates current difficulty based on curriculum settings.
        /// </summary>
        private float CalculateCurrentDifficulty()
        {
            if (!useCurriculum)
            {
                return difficulty;
            }

            // Gradually increase from startDifficulty to difficulty over curriculumSteps
            float progress = Mathf.Min(generationCount / (float)curriculumSteps, 1f);
            return Mathf.Lerp(startDifficulty, difficulty, progress);
        }

        /// <summary>
        /// Clears the current track.
        /// </summary>
        private void ClearTrack()
        {
            foreach (GameObject piece in currentTrackPieces)
            {
                Destroy(piece);
            }

            currentTrackPieces.Clear();
            foreach (GameObject wall in currentWallPieces)
            {
                Destroy(wall);
            }

            currentWallPieces.Clear();
        }

        /// <summary>
        /// Gets statistics about the last generated track (for thesis analysis).
        /// </summary>
        public TrackStats GetLastTrackStats()
        {
            return lastTrackStats;
        }

        /// <summary>
        /// Gets the current generation/episode count.
        /// </summary>
        public int GetGenerationCount()
        {
            return generationCount;
        }

        /// <summary>
        /// Resets the generation counter (useful when switching between NEAT/PPO experiments).
        /// </summary>
        public void ResetGenerationCount()
        {
            generationCount = 0;
        }

        void OnDrawGizmos()
        {
            // Visualize track in editor
            if (currentTrackPieces.Count > 0)
            {
                Gizmos.color = Color.cyan;
                for (int i = 0; i < currentTrackPieces.Count - 1; i++)
                {
                    Gizmos.DrawLine(
                        currentTrackPieces[i].transform.position + Vector3.up * 0.5f,
                        currentTrackPieces[i + 1].transform.position + Vector3.up * 0.5f
                    );
                }
            }
        }

        private void PlaceWall(Vector3 start, Vector3 end, string wallName, float thickness)
        {
            Vector3 diff = end - start;
            //Debug.Log(end + " - " + start + " = " + diff);
            float dist = diff.magnitude;
            if (dist < 0.001f) return;

            Vector3 wallPos = start + diff * 0.5f;
            Quaternion wallRot = Quaternion.LookRotation(diff);

            GameObject wall = Instantiate(wallPrefab, wallPos, wallRot, transform);
            wall.name = wallName;

            // Clean scale: thickness (X), height (Y), and distance (Z)
            // Use 1.0f for Y to preserve prefab height relative to its transform
            wall.transform.localScale = new Vector3(thickness, wall.transform.localScale.y, dist);

            currentWallPieces.Add(wall);
        }

        private enum PieceType
        {
            Straight,
            Turn45Left,
            Turn45Right,
            Turn90Left,
            Turn90Right
        }
    }
}

using CarExperiment;
using UnityEngine;
using Unity.MLAgents;
using Unity.MLAgents.Sensors;
using Unity.MLAgents.Actuators;

public class PPOCarController : Agent
{
    public float Speed = 5f;
    public float TurnSpeed = 180f;
    public float SensorRange = 10f;

    private Rigidbody rb;
    private int currentPiece = 0;
    private int lastPiece = -1;
    private int wallHits = 0;
    private float episodeStartTime;
    private bool goalReached = false;
    private Vector3 startPosition;
    private Quaternion startRotation;
    private TrackGenerator trackGenerator;

    // --- Add these member variables ---
    private Vector3[] lastRayOrigins = new Vector3[5];
    private Vector3[] lastRayDirs = new Vector3[5];
    private float[] lastRayLengths = new float[5];

    private int episodeCount = 0;
    private int fixedUpdateCount = 0; // Added counter for FixedUpdate

    void Start()
    {
        rb = GetComponent<Rigidbody>();
        startPosition = transform.position;
        startRotation = transform.rotation;
    }

    public override void OnEpisodeBegin()
    {
        // Reset episode start time
        episodeStartTime = Time.time;

        // Log the episode data before resetting for the next episode
        Logger.LogEpisode(
            "PPO",
            episodeCount++,
            currentPiece,
            wallHits,
            (currentPiece-1) * 1f - wallHits * 0.2f,
            fixedUpdateCount
        );

        // Debug log for episode start (conditional to avoid flooding)
        if (episodeCount % 100 == 0) // Log every 100 episodes
        {
            Debug.Log("PPO Episode started");
        }

        // Regenerate the track for PPO
        if (trackGenerator == null)
        {
            trackGenerator = FindObjectOfType<TrackGenerator>();
        }
        if (trackGenerator != null)
        {
            int seed = SeedManager.GetSeedForEpisode(episodeCount);
            trackGenerator.GenerateTrack(seed);
        }

        // Reset car position and state
        transform.position = startPosition; // Or starting position
        transform.rotation = startRotation;
        rb.linearVelocity = Vector3.zero;
        rb.angularVelocity = Vector3.zero;
        currentPiece = 0;
        lastPiece = -1;
        wallHits = 0;
        goalReached = false;

        Debug.Log("PPO Episode started");
    }

    public override void CollectObservations(VectorSensor sensor)
    {
        // Same 5 sensors as NEAT version
        float frontSensor = 0;
        float leftFrontSensor = 0;
        float leftSensor = 0;
        float rightFrontSensor = 0;
        float rightSensor = 0;

        RaycastHit hit;
        Vector3 origin = transform.position + transform.forward * 1.1f;

        // Front sensor
        Vector3 dirFront = transform.TransformDirection(Vector3.forward);
        float frontRayLength = SensorRange;
        if (Physics.Raycast(origin, dirFront, out hit, SensorRange))
        {
            if (hit.collider.CompareTag("Wall"))
            {
                frontSensor = 1 - hit.distance / SensorRange;
            }
            frontRayLength = hit.distance;
        }
        lastRayOrigins[0] = origin;
        lastRayDirs[0] = dirFront;
        lastRayLengths[0] = frontRayLength;

        // Right-front sensor
        Vector3 dirRightFront = transform.TransformDirection(new Vector3(0.5f, 0, 1).normalized);
        float rightFrontRayLength = SensorRange;
        if (Physics.Raycast(origin, dirRightFront, out hit, SensorRange))
        {
            if (hit.collider.CompareTag("Wall"))
            {
                rightFrontSensor = 1 - hit.distance / SensorRange;
            }
            rightFrontRayLength = hit.distance;
        }
        lastRayOrigins[1] = origin;
        lastRayDirs[1] = dirRightFront;
        lastRayLengths[1] = rightFrontRayLength;

        // Right sensor
        Vector3 dirRight = transform.TransformDirection(Vector3.right);
        float rightRayLength = SensorRange;
        if (Physics.Raycast(origin, dirRight, out hit, SensorRange))
        {
            if (hit.collider.CompareTag("Wall"))
            {
                rightSensor = 1 - hit.distance / SensorRange;
            }
            rightRayLength = hit.distance;
        }
        lastRayOrigins[2] = origin;
        lastRayDirs[2] = dirRight;
        lastRayLengths[2] = rightRayLength;

        // Left-front sensor
        Vector3 dirLeftFront = transform.TransformDirection(new Vector3(-0.5f, 0, 1).normalized);
        float leftFrontRayLength = SensorRange;
        if (Physics.Raycast(origin, dirLeftFront, out hit, SensorRange))
        {
            if (hit.collider.CompareTag("Wall"))
            {
                leftFrontSensor = 1 - hit.distance / SensorRange;
            }
            leftFrontRayLength = hit.distance;
        }
        lastRayOrigins[3] = origin;
        lastRayDirs[3] = dirLeftFront;
        lastRayLengths[3] = leftFrontRayLength;

        // Left sensor
        Vector3 dirLeft = transform.TransformDirection(Vector3.left);
        float leftRayLength = SensorRange;
        if (Physics.Raycast(origin, dirLeft, out hit, SensorRange))
        {
            if (hit.collider.CompareTag("Wall"))
            {
                leftSensor = 1 - hit.distance / SensorRange;
            }
            leftRayLength = hit.distance;
        }
        lastRayOrigins[4] = origin;
        lastRayDirs[4] = dirLeft;
        lastRayLengths[4] = leftRayLength;

        sensor.AddObservation(frontSensor);
        sensor.AddObservation(leftFrontSensor);
        sensor.AddObservation(leftSensor);
        sensor.AddObservation(rightFrontSensor);
        sensor.AddObservation(rightSensor);
    }

    public override void OnActionReceived(ActionBuffers actions)
    {
        float steer = actions.ContinuousActions[0] * 2 - 1; // -1 to 1
        float gas = actions.ContinuousActions[1];   // 0 to 1
        //for last only: float gas = actions.ContinuousActions[1] * 0.5f + 0.5f; // 0 to 1

        float moveDist = gas * Speed * Time.deltaTime;
        float turnAngle = steer * TurnSpeed * Time.deltaTime * gas;

        transform.Rotate(Vector3.up, turnAngle);
        transform.Translate(Vector3.forward * moveDist);
    }

    public override void Heuristic(in ActionBuffers actionsOut)
    {
        var continuousActionsOut = actionsOut.ContinuousActions;
        continuousActionsOut[0] = Input.GetAxis("Horizontal"); // Steer
        continuousActionsOut[1] = Input.GetAxis("Vertical");   // Gas
    }

    void OnCollisionEnter(Collision collision)
    {
        //Debug.Log($"[COLLISION] With: {collision.collider.name}, Tag: {collision.collider.tag}");
        if (collision.collider.CompareTag("Road"))
        {
            RoadPiece rp = collision.collider.GetComponentInParent<RoadPiece>();
            //Debug.Log(rp == null ? "[COLLISION] No RoadPiece component found!" : $"[COLLISION] RoadPiece found, PieceNumber: {rp.PieceNumber}");
            if (rp != null && rp.PieceNumber != lastPiece && (rp.PieceNumber == currentPiece + 1 || (rp.PieceNumber == 0)))
            {
                lastPiece = currentPiece;
                currentPiece = rp.PieceNumber;
                AddReward(1f); // Reward for reaching next piece
                //Debug.Log($"PPO Piece reached: {CurrentPiece}");
            }
            if (rp != null && rp.PieceNumber == 0 && currentPiece > 0)
            {
                currentPiece = 0;
            }
        }
        else if (collision.collider.CompareTag("Wall"))
        {
            wallHits++;
            AddReward(-0.2f); // Penalty for wall hit
        }
    }

    void OnTriggerEnter(Collider other)
    {
        //Debug.Log($"[TRIGGER] With: {other.name}, Tag: {other.tag}");
        if (other.CompareTag("Road"))
        {
            RoadPiece rp = other.GetComponentInParent<RoadPiece>();
            //Debug.Log(rp == null ? "[TRIGGER] No RoadPiece component found!" : $"[TRIGGER] RoadPiece found, PieceNumber: {rp.PieceNumber}");
            if (rp != null && rp.PieceNumber != lastPiece && (rp.PieceNumber == currentPiece + 1 || (rp.PieceNumber == 0)))
            {
                lastPiece = currentPiece;
                currentPiece = rp.PieceNumber;
                AddReward(1f); // Reward for reaching next piece
                //Debug.Log($"PPO Piece reached: {CurrentPiece}");
            }
            if (rp != null && rp.PieceNumber == 0 && currentPiece > 0)
            {
                currentPiece = 0;
            }
        }
        else if (other.CompareTag("Wall"))
        {
            wallHits++;
            AddReward(-0.2f); // Penalty for wall hit
        }
        else if (other.CompareTag("Goal") && !goalReached)
        {
            goalReached = true;
            float timeTaken = Time.time - episodeStartTime;
            float speedBonus = 100f / Mathf.Max(timeTaken, 0.1f);
            AddReward(speedBonus + 10f); // Big reward for goal + speed bonus

            // Debug log for goal reached (conditional to avoid flooding)
            if (episodeCount % 100 == 0) // Log every 100 episodes
            {
                Debug.Log($"PPO Goal reached! Time: {timeTaken:F2}s, Reward: {speedBonus + 10f:F2}");
            }

            EndEpisode();
        }
    }

    void FixedUpdate()
    {
        fixedUpdateCount++; // Increment counter on each FixedUpdate

        // Draw rays for visualization (only 5 per car per frame, always in the same directions)
        Color[] rayColors = { Color.red, Color.yellow, Color.green, Color.cyan, Color.blue };
        Vector3 origin = transform.position + transform.forward * 1.1f;
        Vector3[] dirs = new Vector3[] {
            transform.TransformDirection(Vector3.forward),
            transform.TransformDirection(new Vector3(0.5f, 0, 1).normalized),
            transform.TransformDirection(Vector3.right),
            transform.TransformDirection(new Vector3(-0.5f, 0, 1).normalized),
            transform.TransformDirection(Vector3.left)
        };
        for (int i = 0; i < 5; i++)
        {
            Debug.DrawRay(origin, dirs[i] * SensorRange, rayColors[i], 0f);
        }

        // Optional: Check for timeout
        if (Time.time - episodeStartTime > 30f) // 30 seconds timeout
        {
            // Log the episode data before ending
            Logger.LogEpisode(
                "PPO",
                episodeCount++,
                currentPiece,
                wallHits,
                GetCumulativeReward(),
                fixedUpdateCount // Added fixed update count to log
            );
            EndEpisode();
        }
    }
}

